// HasWithdrawRequestsWith applies the HasEdge predicate on the "withdraw_requests" edge with a given conditions (other predicates).
func HasWithdrawRequestsWith(preds ...predicate.MerchantWithdrawRequest) predicate.Merchant {
	return predicate.Merchant(func(s *sql.Selector) {
		step := newWithdrawRequestsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasSubUsers applies the HasEdge predicate on the "sub_users" edge.
func HasSubUsers() predicate.Merchant {
	return predicate.Merchant(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, SubUsersTable, SubUsersColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSubUsersWith applies the HasEdge predicate on the "sub_users" edge with a given conditions (other predicates).
func HasSubUsersWith(preds ...predicate.User) predicate.Merchant {
	return predicate.Merchant(func(s *sql.Selector) {
		step := newSubUsersStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Merchant) predicate.Merchant {
	return predicate.Merchant(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Merchant) predicate.Merchant {
	return predicate.Merchant(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Merchant) predicate.Merchant {
	return predicate.Merchant(sql.NotPredicates(p))
}
